const body = $json.body || {};
const itinerary = body.itinerary || {};
const trip = itinerary.trip || {};

const esc = (v) => {
  if (v === null || v === undefined) return '';
  return String(v)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');
};

const city = esc(body.city || trip.city || 'your destination');
const country = esc(trip.country || '');
const numDays = trip.num_days || (Array.isArray(itinerary.days) ? itinerary.days.length : 0);
const interests = Array.isArray(trip.interests) ? trip.interests.map(esc).join(', ') : '';
const pace = esc(trip.pace || '');

const titleCase = (s) => s ? s.charAt(0).toUpperCase() + s.slice(1) : s;

const blockLabels = ['morning', 'afternoon', 'evening'];

const parts = [];
parts.push('<div style="font-family:Arial,Helvetica,sans-serif;color:#222;max-width:680px;margin:0 auto;">');
parts.push('<h1 style="color:#1a73e8;margin-bottom:4px;">' + numDays + '-Day Trip to ' + city + (country ? ', ' + country : '') + '</h1>');

const meta = [];
if (interests) meta.push('<strong>Interests:</strong> ' + interests);
if (pace) meta.push('<strong>Pace:</strong> ' + titleCase(pace));
if (meta.length) {
  parts.push('<p style="color:#555;margin-top:0;">' + meta.join(' &nbsp;&bull;&nbsp; ') + '</p>');
}

const days = Array.isArray(itinerary.days) ? itinerary.days : [];
for (const day of days) {
  const dayIndex = day.day_index || '';
  const theme = esc(day.theme || '');
  parts.push('<h2 style="border-bottom:2px solid #eee;padding-bottom:6px;margin-top:28px;">Day ' + dayIndex + (theme ? ' — ' + theme : '') + '</h2>');

  for (const label of blockLabels) {
    const block = day[label];
    if (!block || !Array.isArray(block.stops) || block.stops.length === 0) continue;
    parts.push('<h3 style="color:#1a73e8;margin-bottom:6px;">' + titleCase(label) + '</h3>');
    parts.push('<ul style="margin-top:0;padding-left:20px;">');
    for (const stop of block.stops) {
      const name = esc(stop.name || 'Unnamed stop');
      const category = esc(stop.category || '');
      const duration = stop.duration_min ? stop.duration_min + ' min' : '';
      const details = [];
      if (category) details.push(titleCase(category));
      if (duration) details.push(duration);
      if (stop.travel_to_next_min && stop.travel_to_next_mode) {
        details.push('then ' + stop.travel_to_next_min + ' min ' + esc(stop.travel_to_next_mode) + ' to next');
      }
      const detailStr = details.length ? ' <span style="color:#777;font-size:13px;">(' + details.join(' · ') + ')</span>' : '';
      parts.push('<li style="margin-bottom:6px;"><strong>' + name + '</strong>' + detailStr + '</li>');
    }
    parts.push('</ul>');
  }
}

if (days.length === 0) {
  parts.push('<p>No itinerary details were included in this request.</p>');
}

parts.push('<hr style="border:none;border-top:1px solid #eee;margin-top:28px;">');
parts.push('<p style="color:#999;font-size:12px;">Travel times are heuristic estimates. Confirm opening hours on-site.</p>');
parts.push('</div>');

const html = parts.join('\n');
const recipient = body.email || 'mpan49@gmail.com';
const subject = numDays + '-Day Itinerary for ' + city;

return { html, recipient, subject };
